def dedup_report(rows, key='id'):
    seen = {}
    unique = []
    conflicts = []
    for row in rows:
        k = row[key]
        if k not in seen:
            seen[k] = row
            unique.append(row)
        else:
            if row != seen[k]:
                conflicts.append({'id': k, 'prev': seen[k], 'new': row})
    return {'unique': unique, 'conflicts': conflicts}

